+@using sv_6998a4047c41408fa41b14bd8e2f93fc.Services
+
+<div class="message-bubble" @onmouseenter="() => _showActions = true" @onmouseleave="() => _showActions = false">
+    <div class="message-header">
+        <span class="author">@Message.Author</span>
+        <span class="timestamp">@FormatRelativeTime(Message.SentAt)</span>
+    </div>
