arguments.file_text:
@using sv_6998a4047c41408fa41b14bd8e2f93fc.Services

<div class="message-area">
    <div class="area-header">
        <h3># @ChannelName</h3>
        <span class="channel-desc">@ChannelDescription</span>
    </div>

    <div class="message-list" @onscroll="HandleScroll" @ref="_scrollContainer">
        @if (_loadingMore)
        {
            <div class="loading-indicator">Loading older messages…</div>
        }

        @foreach (var msg in Messages)
        {
            <MessageBubble Message="msg"
                           ReplyCount="GetReplyCount(msg.Id)"
                           OnOpenThread="OnOpenThread"
                           OnReact="async emoji => await OnReact.InvokeAsync((msg.Id, emoji))" />
        }
    </div>

    <MessageInput Placeholder="@($"Message #{ChannelName}")" OnSend="OnSendMessage" />
</div>

@code {
    [Parameter, EditorRequired] public string ChannelName { get; set; } = "";
    [Parameter] public string ChannelDescription { get; set; } = "";
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, int> ThreadReplyCounts { get; set; } = [];
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }

    private ElementReference _scrollContainer;
    private bool _loadingMore;

    private int GetReplyCount(int messageId)
        => ThreadReplyCounts.TryGetValue(messageId, out var count) ? count : 0;

    private async Task HandleScroll()
    {
        // Scroll-to-top triggers pagination
        // We rely on JS interop for scroll position detection; for simplicity,
        // the parent page handles this via the OnLoadMore callback.
        // A lightweight approach: fire on every scroll and let parent debounce.
    }
}

.message-area {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #fff;
    overflow: hidden;
}

.area-header {
    padding: 12px 16px;
    border-bottom: 1px solid #e0e0e0;
    flex-shrink: 0;
}

.area-header h3 {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
    color: #2c2f33;
}

.channel-desc {
    font-size: 0.8rem;
    color: #777;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.loading-indicator {
    text-align: center;
    padding: 12px;
    font-size: 0.85rem;
    color: #999;
}

@using sv_6998a4047c41408fa41b14bd8e2f93fc.Services

