@page "/chat"
@using sv_6998a4047c41408fa41b14bd8e2f93fc.Services
@using sv_6998a4047c41408fa41b14bd8e2f93fc.Components.Chat
@inject IChatService ChatService
@inject IJSRuntime JS
@implements IAsyncDisposable
@rendermode InteractiveServer

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <div class="chat-sidebar">
        <ChannelSidebar Channels="_channels"
                        ActiveChannelId="_activeChannelId"
                        OnChannelSelected="SelectChannel" />
    </div>

    <div class="chat-main @(_isThreadOpen ? "" : "full-width")">
        @if (_activeChannel is not null)
        {
            <MessageArea ChannelName="@_activeChannel.Name"
                         ChannelDescription="@_activeChannel.Description"
                         Messages="_messages"
                         ThreadReplyCounts="_threadReplyCounts"
                         OnOpenThread="OpenThread"
                         OnSendMessage="SendMessage"
                         OnReact="HandleReaction"
                         OnLoadMore="LoadMoreMessages" />
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (_isThreadOpen)
    {
        <div class="chat-thread">
            <ThreadPanel RootMessage="_threadRootMessage"
                         Replies="_threadReplies"
                         OnClose="CloseThread"
                         OnSendReply="SendThreadReply"
                         OnReact="HandleReaction" />
        </div>
    }
</div>

@code {
    private List<Channel> _channels = [];
    private Channel? _activeChannel;
    private int _activeChannelId;
    private List<Message> _messages = [];
    private Dictionary<int, int> _threadReplyCounts = [];
    private int _skip;
    private const int PageSize = 50;
    private bool _loadingMore;

    // Thread state
    private bool _isThreadOpen;
    private Message? _threadRootMessage;
    private List<Message> _threadReplies = [];

    private IJSObjectReference? _jsModule;
    private DotNetObjectReference<Chat>? _dotNetRef;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await SelectChannel(_channels[0]);
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _dotNetRef = DotNetObjectReference.Create(this);
            _jsModule = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./Components/Pages/Chat.razor.js");
            await _jsModule.InvokeVoidAsync("initScrollDetection", _dotNetRef);
        }
    }

    private async Task SelectChannel(Channel channel)
    {
        _activeChannel = channel;
        _activeChannelId = channel.Id;
        _skip = 0;
        _messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        _skip = _messages.Count;
        await BuildThreadReplyCounts();
        await ChatService.MarkChannelReadAsync(channel.Id);

        // Refresh channels to update unread counts
        _channels = await ChatService.GetChannelsAsync();
        CloseThreadSync();
    }

    private async Task BuildThreadReplyCounts()
    {
        _threadReplyCounts = [];
        // Messages that are thread starters (have replies pointing to them)
        var rootIds = _messages
            .Where(m => m.ReplyToId is null)
            .Select(m => m.Id)
            .ToHashSet();

        foreach (var rootId in rootIds)
        {
            var replies = _messages.Count(m => m.ReplyToId == rootId);
            if (replies > 0)
            {
                _threadReplyCounts[rootId] = replies;
            }
        }
    }

    private async Task SendMessage(string content)
    {
        if (_activeChannel is null) return;
        var msg = await ChatService.SendMessageAsync(_activeChannel.Id, content, null);
        _messages.Add(msg);
        _skip++;
    }

    private async Task OpenThread(int rootMessageId)
    {
        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == rootMessageId);
        if (_threadRootMessage is null) return;

        _threadReplies = await ChatService.GetThreadAsync(rootMessageId);
        _isThreadOpen = true;
    }

    private void CloseThread() => CloseThreadSync();

    private void CloseThreadSync()
    {
        _isThreadOpen = false;
        _threadRootMessage = null;
        _threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (_activeChannel is null || _threadRootMessage is null) return;
        var reply = await ChatService.SendMessageAsync(_activeChannel.Id, content, _threadRootMessage.Id);
        _threadReplies.Add(reply);
        _messages.Add(reply);
        _skip++;

        // Update reply count
        _threadReplyCounts[_threadRootMessage.Id] =
            _threadReplyCounts.GetValueOrDefault(_threadRootMessage.Id) + 1;
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Refresh the affected message in both lists
        if (_activeChannel is not null)
        {
            _messages = await ChatService.GetMessagesAsync(_activeChannel.Id, 0, _skip);
        }

        if (_isThreadOpen && _threadRootMessage is not null)
        {
            _threadReplies = await ChatService.GetThreadAsync(_threadRootMessage.Id);
            _threadRootMessage = _messages.FirstOrDefault(m => m.Id == _threadRootMessage.Id)
                                 ?? _threadRootMessage;
        }
    }

    [JSInvokable]
    public async Task OnScrollToTop()
    {
        if (_activeChannel is null || _loadingMore) return;
        _loadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(_activeChannel.Id, _skip, PageSize);
        if (older.Count > 0)
        {
            _messages.InsertRange(0, older);
            _skip += older.Count;
        }

        _loadingMore = false;
        StateHasChanged();
    }

    private async Task LoadMoreMessages()
    {
        await OnScrollToTop();
    }

    public async ValueTask DisposeAsync()
    {
        if (_jsModule is not null)
        {
            try
            {
                await _jsModule.InvokeVoidAsync("dispose");
                await _jsModule.DisposeAsync();
            }
            catch (JSDisconnectedException) { }
        }
        _dotNetRef?.Dispose();
    }
}

.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
}

.chat-sidebar {
    width: 20%;
    min-width: 200px;
    flex-shrink: 0;
}

.chat-main {
    width: 55%;
    flex-shrink: 0;
    transition: width 0.2s ease;
}

.chat-main.full-width {
    width: 80%;
}

.chat-thread {
    width: 25%;
    min-width: 280px;
    flex-shrink: 0;
}

.no-channel-selected {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 100%;
    color: #999;
    font-size: 1.1rem;
}

let observer = null;
let dotNetRef = null;

export function initScrollDetection(dotNetObjRef) {
    dotNetRef = dotNetObjRef;

    // Find all .message-list elements and watch for scroll-to-top
    const messageList = document.querySelector('.message-list');
    if (!messageList) return;

    messageList.addEventListener('scroll', handleScroll);
}

function handleScroll(e) {
    const el = e.target;
    if (el.scrollTop <= 10 && dotNetRef) {
        dotNetRef.invokeMethodAsync('OnScrollToTop');
    }
}

export function dispose() {
    const messageList = document.querySelector('.message-list');
    if (messageList) {
        messageList.removeEventListener('scroll', handleScroll);
    }
    dotNetRef = null;
}

